44.         /// Sets the api versions from an Azure Stack profile.
45.         /// </summary>
46.         public void SetApiVersionsFromProfile(AzureStackProfile profile)
47.         {
48.             var assembly = Assembly.GetExecutingAssembly();
49.             using (Stream stream = assembly.GetManifestResourceStream(profile.GetManifestName()))
50.             {
51.                 var span = BinaryData.FromStream(stream).ToMemory().Span;
52.                 var allProfile = JsonSerializer.Deserialize<Dictionary<string, Dictionary<string, JsonElement>>>(span);
53.                 var armProfile = allProfile["resource-manager"];
54.                 foreach (var keyValuePair in armProfile)
55.                 {
56.                     var namespaceName = keyValuePair.Key;
57.                     var element = keyValuePair.Value;
58. 
59.                     foreach (var apiVersionProperty in element.EnumerateObject())
60.                     {
61.                         var apiVersion = apiVersionProperty.Name;
62.                         foreach (var resourceTypeItem in apiVersionProperty.Value.EnumerateArray())
63.                         {
64.                             string resourceTypeName = default;
